class Solution:
    def resultsArray(self, nums, k):
        n = len(nums)
        res = []
        for i in range(n - k + 1):
            window = nums[i:i + k]
            ok = all(window[t] + 1 == window[t + 1] for t in range(len(window) - 1))
            res.append(window[-1] if ok else -1)
        return res

