class Solution:
    def resultsArray(self, nums, k):
        n = len(nums)
        run = [0] * n
        for j in range(1, n):
            if nums[j] == nums[j - 1] + 1:
                run[j] = run[j - 1] + 1
        res = []
        for i in range(n - k + 1):
            end = i + k - 1
            res.append(nums[end] if run[end] >= k - 1 else -1)
        return res

