var resultsArray = function(nums, k) {
    const n = nums.length;
    const run = new Array(n).fill(0);
    for (let j = 1; j < n; j++) {
        if (nums[j] === nums[j - 1] + 1) run[j] = run[j - 1] + 1;
    }
    const res = [];
    for (let i = 0; i <= n - k; i++) {
        const end = i + k - 1;
        res.push(run[end] >= k - 1 ? nums[end] : -1);
    }
    return res;
};
